                let y_boot = y.select(Axis(0), &indices);

                // Compute statistic
                statistic.compute(x_boot.view(), y_boot.view())
            })
            .collect()
    } else {
        // Sequential version for reproducible results with seed
        let mut rng = if let Some(seed) = config.seed {
            rand::rngs::StdRng::seed_from_u64(seed)
        } else {
            rand::rngs::StdRng::from_entropy()
        };

        (0..config.n_samples)
            .map(|_| {
                let indices: Vec<usize> = (0..n_obs)
                    .map(|_| rng.gen_range(0..n_obs))
                    .collect();

