                statistic.compute(x_boot.view(), y_boot.view())
            })
            .collect()
    };

    // Combine results into matrix
    let mut statistics = Array2::zeros((config.n_samples, n_stats));
    for (i, stat) in bootstrap_stats.iter().enumerate() {
        statistics.row_mut(i).assign(stat);
    }

    // Compute estimates and standard errors
    let estimates = statistics.mean_axis(Axis(0)).unwrap();
    let std_errors = statistics.std_axis(Axis(0), 0.0);

    Ok(BootstrapResult {
        statistics,
        estimates,
        std_errors,
        confidence_intervals: None,
    })
}

/// Compute confidence intervals from bootstrap distribution
pub fn bootstrap_confidence_intervals(
    result: &mut BootstrapResult,
    alpha: f64,
) -> Result<(), ResampleError> {
    let confidence_level = 1.0 - alpha;
    let lower_percentile = alpha / 2.0;
    let upper_percentile = 1.0 - alpha / 2.0;

    let n_stats = result.statistics.ncols();
    let mut intervals = Array2::zeros((n_stats, 2));

    for j in 0..n_stats {
        let mut values: Vec<f64> = result.statistics.column(j).to_vec();
        values.sort_by(|a, b| a.partial_cmp(b).unwrap());

        let n = values.len();
        let lower_idx = ((n as f64) * lower_percentile).floor() as usize;
        let upper_idx = ((n as f64) * upper_percentile).ceil() as usize - 1;

        intervals[[j, 0]] = values[lower_idx.min(n - 1)];
        intervals[[j, 1]] = values[upper_idx.min(n - 1)];
    }

    result.confidence_intervals = Some(intervals);
    Ok(())
}

/// Jackknife resampling (leave-one-out)
///
/// Computes the jackknife estimate by systematically leaving out one observation
/// at a time and computing the statistic on the remaining data.
pub fn jackknife<S>(
    x: ArrayView2<f64>,
    y: ArrayView1<f64>,
    statistic: S,
) -> Result<BootstrapResult, ResampleError>
where
    S: BootstrapStatistic + Sync + Send,
{
    let n_obs = x.nrows();
    let n_stats = statistic.n_stats();

    if n_obs <= 1 {
        return Err(ResampleError::InsufficientData(2));
    }

    let statistic = Arc::new(statistic);

    // Parallel jackknife computation
    let jackknife_stats: Vec<Array1<f64>> = (0..n_obs)
        .into_par_iter()
        .map(|i| {
            // Create indices excluding observation i
            let indices: Vec<usize> = (0..n_obs).filter(|&idx| idx != i).collect();

            // Create jackknife sample
            let x_jack = x.select(Axis(0), &indices);
            let y_jack = y.select(Axis(0), &indices);

            // Compute statistic
            statistic.compute(x_jack.view(), y_jack.view())
        })
        .collect();

    // Combine results into matrix
    let mut statistics = Array2::zeros((n_obs, n_stats));
    for (i, stat) in jackknife_stats.iter().enumerate() {
        statistics.row_mut(i).assign(stat);
    }

    // Compute jackknife estimates and standard errors
    let estimates = statistics.mean_axis(Axis(0)).unwrap();

    // Jackknife standard error formula: sqrt((n-1)/n * sum((theta_i - theta_bar)^2))
    let n = n_obs as f64;
    let variance = statistics.map_axis(Axis(0), |column| {
        let mean = column.mean().unwrap();
        let sum_sq_diff: f64 = column.iter()
            .map(|&x| (x - mean).powi(2))
            .sum();
        ((n - 1.0) / n) * sum_sq_diff
    });
    let std_errors = variance.mapv(f64::sqrt);

    Ok(BootstrapResult {
        statistics,
        estimates,
        std_errors,
        confidence_intervals: None,
    })
}

